from rank_bm25 import BM25Okapi

# búsqueda léxica con BM25
corpus_tokenizado = [chunk.lower().split() for chunk in todos_los_chunks]
bm25 = BM25Okapi(corpus_tokenizado)
query_tokens = "código de error E04 fallo de pago".lower().split()
scores = bm25.get_scores(query_tokens)
top_k_bm25 = sorted(zip(todos_los_chunks, scores), key=lambda x: x[1], reverse=True)[:5]

# fusión de rankings: vectorial + BM25
def reciprocal_rank_fusion(ranking_vectorial, ranking_bm25, k=60):
    scores = {}
    for rank, (chunk_id, _) in enumerate(ranking_vectorial):
        scores[chunk_id] = scores.get(chunk_id, 0) + 1 / (k + rank)
    for rank, (chunk_id, _) in enumerate(ranking_bm25):
        scores[chunk_id] = scores.get(chunk_id, 0) + 1 / (k + rank)
    return sorted(scores.items(), key=lambda x: x[1], reverse=True)

# re-ranking con Claude (para corpus moderados)
tool_relevancia = {
    "name": "puntuar_relevancia",
    "description": "Puntúa qué tan relevante es un fragmento para la pregunta",
    "input_schema": {
        "type": "object",
        "properties": {"puntaje": {"type": "number", "minimum": 0, "maximum": 1}},
        "required": ["puntaje"],
    },
}

def puntuar(pregunta, chunk):
    r = client.messages.create(
        model="claude-haiku-4-5-20251001", max_tokens=50,
        tools=[tool_relevancia], tool_choice={"type": "tool", "name": "puntuar_relevancia"},
        messages=[{"role": "user", "content": f"Pregunta: {pregunta}\nFragmento: {chunk}"}],
    )
    return r.content[0].input["puntaje"]

candidatos_reordenados = sorted(candidatos_top_20, key=lambda c: puntuar(pregunta, c), reverse=True)[:5]

