# Formato de salida de un subagente de análisis de documentos:
# separa el contenido (claim) de su metadata (fuente, fecha, ubicación)

hallazgo_schema = {
    "type": "object",
    "required": ["claim", "source", "published_date", "excerpt"],
    "properties": {
        "claim": {"type": "string"},
        "source": {
            "type": "object",
            "required": ["name", "url_or_doc_id"],
            "properties": {
                "name": {"type": "string"},
                "url_or_doc_id": {"type": "string"},
                "page": {"type": ["integer", "null"]},
            },
        },
        "published_date": {"type": ["string", "null"]},
        "excerpt": {"type": "string"},
    },
}

# ejemplo de hallazgo bien formado
hallazgo = {
